// Extract router JSON from Groq response
const raw = $json.choices?.[0]?.message?.content || '{}';
let routed;
try { routed = JSON.parse(raw); } catch { routed = { action: 'chitchat', payload: {}, expected_format: 'text' }; }
const question = $('Validate payload').item.json.question;
return [{ json: { ...routed, originalQuestion: question } }];

// Branche KB : pas d'appel API, on retourne juste l'action et la question.
const routed = $json;
return [{ json: { __isKb: true, originalQuestion: routed.originalQuestion, action: 'kb' } }];

// Construit le prompt de reformulation à partir de la question + data API.
const routed = $('Parse routing JSON').first().json;
const data = $json;
const question = routed.originalQuestion;
const action = routed.action;

let contextHint = '';
if (data.__isKb) {
  contextHint = `Question conceptuelle. Réponds en t'appuyant sur ta connaissance du projet (système COD Tunisie, 4 rôles, BC/BL, réclamations, demandes, attribution conf, lock 15min, escalation 3 tentatives, etc.). Une à trois phrases, ton clair et professionnel.`;
} else if (action === 'query') {
  contextHint = `Tu as appelé l'API /chat/query et tu as reçu un JSON. Le champ 'value' = chiffre principal, 'rows' = lignes liste, 'series' = points pour graphe. Si 'rows' est rempli, tu peux résumer 1-2 lignes ou indiquer le nombre. Si 'series' est rempli, tu décris la tendance globale. N'INVENTE PAS de chiffres absents du JSON.`;
} else if (action === 'analyze') {
  contextHint = `Tu as appelé /chat/analyze. Le JSON contient une analyse statistique (trend, compare, anomaly, correlation, distribution). Décris le résultat en français clair, mentionne les chiffres clés (slope, R², z-score, percentiles selon le cas).`;
} else if (action === 'predict') {
  contextHint = `Tu as appelé /chat/predict. Le JSON contient une prédiction ML (probabilité 0-1 ou valeur prévue). Donne le résultat avec le pourcentage si applicable, l'explication si fournie, et la métadonnée du modèle (type, source données).`;
}

const prompt = `Question utilisateur : ${question}\n\n${contextHint}\n\nRéponse de l'API :\n${JSON.stringify(data, null, 2)}\n\nRédige une réponse naturelle en français (1-3 phrases), claire, sans inventer de chiffres.`;

return [{ json: { prompt, action, data, originalQuestion: question } }];

