// Construit la réponse finale Flutter (text + optional chart series)
const groqText = $json.choices?.[0]?.message?.content || 'Réponse indisponible.';
const built = $('Build reformulation prompt').first().json;
const data = built.data || {};

// Détecte si la réponse contient des séries à afficher en graphe
let chart = null;
if (Array.isArray(data.series) && data.series.length > 0) {
  chart = { type: 'bar', points: data.series };
} else if (Array.isArray(data.forecast) && data.forecast.length > 0) {
  chart = { type: 'line', points: data.forecast.map(p => ({ bucket: p.date, value: p.value, lower: p.lowerBound, upper: p.upperBound })) };
} else if (Array.isArray(data.compare) && data.compare.length > 0) {
  chart = { type: 'bar', points: data.compare.map(g => ({ bucket: g.label, value: g.value })) };
} else if (Array.isArray(data.anomalies) && data.anomalies.length > 0 && Array.isArray(data.series)) {
  chart = { type: 'line', points: data.series, anomalies: data.anomalies };
}

const rows = Array.isArray(data.rows) ? data.rows : null;

return [{ json: {
  success: true,
  message: groqText.trim(),
  action: built.action,
  data,
  rows,
  chart
}}];

// Branche chitchat — pas d'appel API, juste réponse polie immédiate.
const routed = $json;
const q = (routed.originalQuestion || '').toLowerCase();
let message;
if (/bonjour|salut|hello|coucou/.test(q)) message = "Bonjour ! Je suis l'assistant métier de votre plateforme de livraison. Je peux répondre aux questions sur les commandes, réclamations, livreurs, produits, prédictions et statistiques.";
else if (/merci/.test(q)) message = "Avec plaisir.";
else if (/qui es.tu|tu es qui|c.est quoi/.test(q)) message = "Je suis l'assistant LLM de votre plateforme COD. Je peux répondre aux questions chiffrées, conceptuelles, analytiques et prédictives sur les commandes, livraisons et réclamations.";
else message = "Je peux vous aider sur les commandes, réclamations, livreurs, produits, statistiques et prédictions. Que voulez-vous savoir ?";
return [{ json: { success: true, message, action: 'chitchat', data: null, rows: null, chart: null } }];
